import { useEffect, useState } from "react";

export default function DuckHunt() {
  const [score, setScore] = useState(0);
  const [x, setX] = useState(0);
  const [y, setY] = useState(0);
  const [alive, setAlive] = useState(true);

  function spawnDuck() {
    setX(Math.random() * 350);
    setY(Math.random() * 250);
    setAlive(true);
  }

  function killDuck() {
    if (!alive) return;

    setScore(score + 1);
    setAlive(false);

    setTimeout(spawnDuck, 200);
  }

  useEffect(() => {
    spawnDuck();

    const id = setInterval(() => {
      if (alive) {
        spawnDuck();
      }
    }, 1000);

    return () => clearInterval(id);
  }, [alive]);

  return (
    <div className="container">
      <h1>🔫 Duck Hunt</h1>

      <h2>Score: {score}</h2>

      <div
        style={{
          position: "relative",
          width: 400,
          height: 300,
          cursor: "crosshair",
        }}
      >
        <div
          style={{
            position: "absolute",
            left: x,
            top: y,
            fontSize: "2.5rem",
            userSelect: "none",
          }}
          onClick={killDuck}
        >
          {alive ? "🦆" : "💥"}
        </div>
      </div>
    </div>
  );
}
